tool.command:
@CMD_UNZIP_ZARR@
mkdir -p output_dir &&
## Run patchify sopa patchify #if $patch_type.type == 'image' image --patch-width-pixel $patch_type.patch_width_pixel --patch-overlap-pixel $patch_type.patch_overlap_pixel #else transcripts --patch-width-microns $patch_type.patch_width_microns --patch-overlap-microns $patch_type.patch_overlap_microns #if str($patch_type.unassigned_value) != '' --unassigned-value '$patch_type.unassigned_value' #end if #if str($patch_type.prior_shapes_key) != '' --prior-shapes-key '$patch_type.prior_shapes_key' #end if $patch_type.write_cells_centroids #end if input/spatialdata.zarr &&
## Move to output directory mv "input/spatialdata.zarr" output_dir/ &&
@CMD_ZIP_ZARR@
